import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    token: localStorage.getItem('lims_dd_token') ? localStorage.getItem('lims_dd_token') : '',
    entrustInfo: localStorage.getItem('entrustInfo') ? localStorage.getItem('entrustInfo') : '',
    sampleList: localStorage.getItem('sampleList') ? localStorage.getItem('sampleList') : localStorage.setItem('sampleList', JSON.stringify([])),
    userid: localStorage.getItem('userid') ? localStorage.getItem('userid') : '',
    adminId: localStorage.getItem('adminId') ? localStorage.getItem('adminId') : '',
    lims_name: localStorage.getItem('lims_name') ? localStorage.getItem('lims_name') : '',

  },
  mutations: {

    setlims_name(state, lims_name) {
      state.lims_name = lims_name;
      localStorage.setItem("lims_name", lims_name);
    },
    dellims_name(state) {
      state.lims_name = '';
      localStorage.removeItem("lims_name");
    },

    setadminId(state, adminId) {
      state.adminId = adminId;
      localStorage.setItem("adminId", adminId);
    },
    deladminId(state) {
      state.adminId = '';
      localStorage.removeItem("adminId");
    },


    setuserid(state, userid) {
      state.userid = userid;
      localStorage.setItem("userid", userid);
    },
    deluserid(state) {
      state.userid = '';
      localStorage.removeItem("userid");
    },

    setToken(state, token) {
      state.token = token;
      localStorage.setItem("lims_dd_token", token.token); //存储token
    },
    delToken(state) {
      state.token = '';
      localStorage.removeItem("lims_dd_token"); //删除token
    },


    setentrustInfo(state, entrustInfo) {
      state.entrustInfo = entrustInfo;
      localStorage.setItem("entrustInfo", JSON.stringify(entrustInfo));
    },
    delentrustInfo(state) {
      state.entrustInfo = '';
      localStorage.removeItem("entrustInfo");
    },

    setsampleList(state, FormItem) {
      let arr = JSON.parse(localStorage.getItem('sampleList'))
      arr.push(FormItem)
      localStorage.setItem('sampleList', JSON.stringify(arr))
      state.sampleList = JSON.stringify(arr)


    },
    deltotalsampleList(state) {
      state.sampleList = ''
      localStorage.setItem('sampleList', JSON.stringify([]))
    },
    delsampleList(state, i) {
      let arr = JSON.parse(localStorage.getItem('sampleList'));
      arr.splice(i, 1)
      localStorage.setItem('sampleList', JSON.stringify(arr))
      state.sampleList = JSON.stringify(arr)


    }
  },
  actions: {},
  modules: {}
})