import http from './request';

// 登入
export function getlogin(values) {
  return http.post('/lims/admin/login', {
    nick: values.nick,
    passWord: values.passWord
  })
}

// 获取下拉框数据
export function getselectlist() {
  return http.get('/lims/entrust/get_select_lists')
}

// 查询产品类型
export function getproducttype() {
  return http.get('/lims/product/product_types')
}

// 查询产品
export function getproduct(type) {
  return http.get('/lims/product/products', {
    type
  })
}
// 判定依据
export function getproductbasis(productId) {
  return http.get('/lims/entrust/get_check_basis', {
    productId
  })
}
// 检测项目
export function getcheckitem(productId) {
  return http.get('/lims/entrust/get_check_items', {
    productId
  })
}

//保存 
export function postcun(entrustInfo, sampleList) {
  return http.post('/lims/entrust/add', {
    entrustInfo,
    sampleList
  })
}

// 我的委托、历史列表

export function getuserlist(info) {
  return http.get('/lims/entrust/ownerTask', {
    type: info.type,
    userId: info.userId,
    adminId: info.adminId,
    startTime: info.startTime,
    endTime: info.endTime,
    pageNo: info.pageNo,
    pageSize: info.pageSize
  })
}

// 再来一单
export function getistas(entrustNumber) {
  return http.get('/lims/entrust/once_more', {
    entrustNumber
  })
}

// 委托单数量、历史委托数量
export function getcount(adminId) {
  return http.get('/lims/entrust/count', {
    adminId
  })
}
// 下载报告

export function getloadurl(sampleId,entrustId) {
  return http.get('/lims/entrust/downloadReport', {
    sampleId: sampleId * 1,
    entrustId: entrustId.toString()
  })
}