<template>
  <div class="login">
    <div class="fix">
      <van-icon name="arrow-left" @click="onClickLeft" />
    </div>
    <div class="login_img_login">
      <img src="../../assets/login/logo.png" alt="" />
      <span>河南交科院</span>
    </div>

    <van-form @submit="onSubmit">
      <van-row>
        <van-col span="2"> </van-col>
        <van-col span="2">
          <span class="iconfont i1">&#xe626;</span>
        </van-col>
        <van-col span="18">
          <van-field
            v-model="nick"
            name="nick"
            placeholder="用户名"
            :rules="[{ required: true, message: '请填写用户名' }]"
          />
        </van-col>
        <van-col span="2"> </van-col>
      </van-row>
      <van-row>
        <van-col span="2"> </van-col>
        <van-col span="2">
          <span class="iconfont i2">&#xe654;</span>
        </van-col>

        <van-col span="18">
          <van-field
            v-model="passWord"
            type="password"
            name="passWord"
            placeholder="密码"
            :rules="[{ required: true, message: '请填写密码' }]"
          />
        </van-col>
        <van-col span="2"> </van-col>
      </van-row>

      <div style="margin: 30px">
        <van-button
          round
          block
          type="info"
          native-type="submit"
          color="linear-gradient(to right, #1989fa, #a270d0)"
          >登入</van-button
        >
      </div>
      <div class="message">
        <a>忘记密码?</a>
      </div>
    </van-form>
  </div>
</template>

<script>
import { getlogin } from "../../utils/http/api";
import { mapMutations } from "vuex";
import { Toast } from "vant";
export default {
  name: "login",
  data() {
    return {
      nick: "",
      passWord: "",
    };
  },
  methods: {
    ...mapMutations(["setToken", "setuserid", "setadminId", "setlims_name"]),
    onClickLeft() {
      this.$router.go(-1);
    },
    onSubmit(values) {
      const toast = Toast.loading({
        message: "加载中...",
        forbidClick: true,
      });
      getlogin(values).then(
        (res) => {
          // console.log(res);

          if (res.data.code === 200) {
            Toast.clear();
            this.setadminId(res.data.data.adminId);
            this.setuserid(res.data.data.userInfo.userId);
            this.setlims_name(res.data.data.name);
            this.setToken({ token: res.data.data.token });

            this.$router.replace({ path: "/case" });
            Toast("登入成功");
          } else {
            Toast.clear();
            Toast(res.data.msg);
          }
        },
        (err) => {
          Toast("网络异常");

          Toast.clear();
        }
      );
    },
  },
};
</script>

<style lang="less">
.login {
  width: 7.5rem;
  height: 13.34rem;
  background-image: url("../../assets/login/shouye.png");
  background-size: 100% 100%;
  overflow: hidden;
  .fix {
    position: fixed;
    width: 100%;
    padding: 10px;
    display: flex;
    align-items: center;
    margin-top: 10px;

    margin-left: 10px;

    i {
      font-size: 20px;
    }
  }
  .van-col--2 {
    height: 0.88rem;
    display: flex;
    justify-content: center;
    align-items: center;
  }
  .van-cell {
    background: rgba(255, 255, 255, 0);
  }
  .i1 {
    font-size: 0.6rem;
    color: #1989fa;
  }
  .i2 {
    font-size: 0.4rem;
    color: #1989fa;
  }
  .van-field__control {
    border-bottom: 1px solid #1989fa;
  }
  input::-webkit-input-placeholder {
    color: #4fa7ff;
  }
  .login_img_login {
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    height: 4rem;
    margin-top: 1.9rem;
    span {
      margin-top: 0.4rem;
      font-size: 0.4rem;
      font-weight: 600;
    }
    img {
      width: 2rem;
      height: 2rem;
    }
  }
  .van-form {
    margin-top: 0.5rem;
  }
  .message {
    display: flex;
    flex-direction: row-reverse;
    padding-left: 0.8rem;
    padding-right: 0.8rem;
    a {
      font-size: 0.24rem;
      color: @blue;
    }
  }
}
</style>