import Vue from 'vue'
import VueRouter from 'vue-router'
import Login from '../views/login/Login.vue'
import {
  Toast
} from 'vant';

Vue.use(VueRouter)

// 解决重复点击导航路由报错
const originalPush = VueRouter.prototype.push;
VueRouter.prototype.push = function push(location) {
  return originalPush.call(this, location).catch(err => err);
}

const routes = [

  {
    path: '/',
    redirect: '/case'
  },
  {
    path: '/login',
    name: 'login',
    meta: {
      auto: false
    },
    component: Login
  },
  {
    path: '/qrcode',
    name: 'qrcode',
    meta: {
      auto: true
    },
    component: () => import('../views/Qrcode.vue')
  },
  {
    path: '/home/ista',
    name: 'ista',
    meta: {
      auto: true
    },
    component: () => import('../views/home/Ista.vue')

  },
  {
    path: '/home/ista/sample',
    name: 'sample',
    meta: {
      auto: true
    },
    component: () => import('../views/home/Sample.vue')

  },
  {
    path: '/home/ista/istalist',
    name: 'istalist',
    meta: {
      auto: true
    },
    component: () => import('../views/home/Istalist.vue')
  },
  {
    path: '/loadcheck',
    name: 'loadcheck',
    meta: {
      auto: true
    },
    component: () => import('../views/Loadcheck.vue')
  },
  {
    path: '/index/myista',
    name: 'myista',
    meta: {
      auto: true
    },
    component: () => import('../views/my/Myista.vue')
  },
  {
    path: '/index/Istaproductdetail',
    name: 'Istaproductdetail',
    meta: {
      auto: true
    },
    component: () => import('../views/my/Istaproductdetail.vue')
  },
  {
    path: '/index/myhistory',
    name: 'myhistory',
    meta: {
      auto: true
    },
    component: () => import('../views/my/Myhistory.vue')
  },
  {
    path: '/index/addresslist',
    name: 'addresslist',
    meta: {
      auto: true
    },
    component: () => import('../views/my/Addresslist.vue')
  },
  {
    path: '/index/setuplist',
    name: 'setuplist',
    meta: {
      auto: true
    },
    component: () => import('../views/my/Setuplist.vue')
  },
  {
    path: '/index/addresslist/addressupdate',
    name: 'addressupdate',
    meta: {
      auto: true
    },
    component: () => import('../views/my/Addressupdate.vue')
  },


  {
    path: '/case',
    name: 'case',
    meta: {
      auto: false
    },
    component: () => import('../views/Case.vue'),
    redirect: '/home',
    children: [{
        path: '/index',
        name: 'index',
        meta: {
          auto: false
        },
        component: () => import('../views/my/Index.vue')
      },
      {
        path: '/home',
        name: 'home',
        meta: {
          auto: false
        },
        component: () => import('../views/home/Home.vue')
      }
    ]
  },

]

const router = new VueRouter({
  routes
})

router.beforeEach((to, from, next) => {

  if (to.path === '/login') { //若要跳转的页面是登录界面
    next(); //直接跳转
  } else if (to.meta.auto) { //若要跳转的页面是个人界面
    let token = localStorage.getItem('lims_dd_token'); //获取本地存储的token值
    if (token === null || token === '') { //若token为空则验证不成功，跳转到登录页面
      Toast('请先登入');
      next('/login');
    } else { //不为空则验证成功
      next();
    }
  } else {
    next();
  }

  // next();




})

export default router